static bool ui_is_custom_font(const lv_font_t *font) {
    if (!font) return false;
    for (size_t i = 0; i < (sizeof(s_ui_fonts) / sizeof(s_ui_fonts[0])); i++) {
        if (s_ui_fonts[i] == font) return true;
    }
    return false;
}

static const lv_font_t *ui_pick_scaled_font(const lv_font_t *orig, int32_t zoom_256) {
    if (!orig) return orig;
    if (!ui_is_custom_font(orig)) return orig;
    if (zoom_256 <= 0) return orig;
    if (zoom_256 >= 256) return orig;

    const int32_t target = ((int32_t)orig->line_height * zoom_256) / 256;
    const lv_font_t *best = orig;
    int32_t best_delta = 0x7FFFFFFF;

    for (size_t i = 0; i < (sizeof(s_ui_fonts) / sizeof(s_ui_fonts[0])); i++) {
        const lv_font_t *cand = s_ui_fonts[i];
        if (!cand) continue;
        const int32_t h = (int32_t)cand->line_height;
        if (h <= 0) continue;
        if (h > target + 1) continue;
        const int32_t delta = (target - h);
        if (delta < best_delta) {
            best_delta = delta;
            best = cand;
        }
    }

    if (best != orig) return best;

    const lv_font_t *smallest = s_ui_fonts[0];
    for (size_t i = 0; i < (sizeof(s_ui_fonts) / sizeof(s_ui_fonts[0])); i++) {
        const lv_font_t *cand = s_ui_fonts[i];
        if (!cand) continue;
        if (!smallest || cand->line_height < smallest->line_height) smallest = cand;
    }
    return smallest ? smallest : orig;
}

static void ui_copy_utf8_trunc(char *dst, size_t dst_sz, const char *src) {
    if (!dst || dst_sz == 0) return;
    if (!src) src = "";
    size_t n = 0;
    while (src[n] != '\0' && n + 1 < dst_sz) {
        dst[n] = src[n];
        n++;
    }
    dst[n] = '\0';
    if (n == 0) return;

    size_t start = n;
    while (start > 0 && (((unsigned char)dst[start - 1] & 0xC0U) == 0x80U)) {
        start--;
    }
    if (start == n) return;

    const unsigned char lead = (unsigned char)dst[start];
    size_t need = 1;
    if ((lead & 0x80U) == 0x00U) need = 1;
    else if ((lead & 0xE0U) == 0xC0U) need = 2;
    else if ((lead & 0xF0U) == 0xE0U) need = 3;
    else if ((lead & 0xF8U) == 0xF0U) need = 4;
    else {
        dst[start] = '\0';
        return;
    }
    if (n - start < need) dst[start] = '\0';
}

static void ui_copy_utf8_sanitized(char *dst, size_t dst_sz, const char *src) {
    if (!dst || dst_sz == 0) return;
    if (!src) src = "";

    size_t di = 0;
    size_t si = 0;
    while (src[si] != '\0' && di + 1 < dst_sz) {
        const unsigned char c = (unsigned char)src[si];
        if (c < 0x80U) {
            if (c >= 0x20U || c == '\t' || c == ' ') dst[di++] = (char)c;
            else dst[di++] = '?';
            si++;
            continue;
        }

        size_t need = 0;
        if ((c & 0xE0U) == 0xC0U) need = 2;
        else if ((c & 0xF0U) == 0xE0U) need = 3;
        else if ((c & 0xF8U) == 0xF0U) need = 4;
        else {
            dst[di++] = '?';
            si++;
            continue;
        }

        bool ok = true;
        for (size_t j = 1; j < need; j++) {
            const unsigned char cc = (unsigned char)src[si + j];
            if (cc == 0 || (cc & 0xC0U) != 0x80U) {
                ok = false;
                break;
            }
        }
        if (!ok || di + need >= dst_sz) {
            dst[di++] = '?';
            si++;
            continue;
        }

        for (size_t j = 0; j < need; j++) dst[di++] = src[si + j];
        si += need;
    }
    dst[di] = '\0';
}

static void disable_scrolling(lv_obj_t *obj) {
    if (!obj) return;
    lv_obj_remove_flag(obj, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_scroll_dir(obj, LV_DIR_NONE);
    lv_obj_set_scrollbar_mode(obj, LV_SCROLLBAR_MODE_OFF);
}

static void disable_scrolling_recursive(lv_obj_t *obj) {
    if (!obj) return;
    disable_scrolling(obj);
    uint32_t i = 0;
    while (true) {
        lv_obj_t *child = lv_obj_get_child(obj, i);
        if (!child) break;
        disable_scrolling_recursive(child);
        i++;
    }
}

static lv_coord_t mul_zoom(lv_coord_t v, int32_t zoom_256) {
    return (lv_coord_t)(((int64_t)v * (int64_t)zoom_256) / 256);
}

static void ui_rescale_yield() {
#if defined(ESP_PLATFORM)
    (void)esp_task_wdt_reset();
    taskYIELD();
#endif
}

static void rescale_obj_tree(lv_obj_t *obj, int32_t zoom_256, lv_coord_t add_x, lv_coord_t add_y) {
    if (!obj) return;

    static uint32_t s_nodes = 0;
    s_nodes++;
    if ((s_nodes & 0x07u) == 0) {
        ui_rescale_yield();
    }

    if (lv_obj_check_type(obj, &lv_label_class)) {
        const lv_font_t *font = lv_obj_get_style_text_font(obj, LV_PART_MAIN);
        const lv_font_t *scaled = ui_pick_scaled_font(font, zoom_256);
        if (scaled && scaled != font) {
            lv_obj_set_style_text_font(obj, scaled, LV_PART_MAIN | LV_STATE_DEFAULT);
        }
    }

    const lv_coord_t old_x = lv_obj_get_x(obj);
    const lv_coord_t old_y = lv_obj_get_y(obj);
    lv_obj_set_pos(obj, (lv_coord_t)(add_x + mul_zoom(old_x, zoom_256)), (lv_coord_t)(add_y + mul_zoom(old_y, zoom_256)));

    const bool is_label = lv_obj_check_type(obj, &lv_label_class);
    if (!is_label) {
        const lv_coord_t w = lv_obj_get_width(obj);
        const lv_coord_t h = lv_obj_get_height(obj);
        if (w > 0) lv_obj_set_width(obj, (lv_coord_t)LV_MAX(1, mul_zoom(w, zoom_256)));
        if (h > 0) lv_obj_set_height(obj, (lv_coord_t)LV_MAX(1, mul_zoom(h, zoom_256)));
    }

    if (lv_obj_check_type(obj, &lv_image_class)) {
        const uint16_t z = lv_img_get_zoom(obj);
        const uint16_t nz = (uint16_t)LV_MAX(1, ((uint32_t)z * (uint32_t)zoom_256) / 256u);
        lv_img_set_zoom(obj, nz);
    }

    uint32_t i = 0;
    while (true) {
        lv_obj_t *child = lv_obj_get_child(obj, i);
        if (!child) break;
        rescale_obj_tree(child, zoom_256, 0, 0);
        i++;
    }
}

static void ui_fit_screen_to_display(lv_obj_t *screen) {
    if (!screen) return;
    if (lv_obj_has_flag(screen, LV_OBJ_FLAG_USER_4)) return;

#if defined(ESP_PLATFORM) && defined(CONFIG_IDF_TARGET_ESP32P4)
    return;
#endif

    lv_disp_t *disp = lv_disp_get_default();
    if (!disp) return;

    const int32_t hor = (int32_t)lv_disp_get_hor_res(disp);
    const int32_t ver = (int32_t)lv_disp_get_ver_res(disp);
    if (hor <= 0 || ver <= 0) return;

    const int32_t design_w = 800;
    const int32_t design_h = 480;

    disable_scrolling(screen);
    lv_obj_set_pos(screen, 0, 0);
    lv_obj_set_size(screen, hor, ver);

    const int32_t zoom_w = (hor * 256) / design_w;
    const int32_t zoom_h = (ver * 256) / design_h;
    const int32_t zoom = (zoom_w < zoom_h) ? zoom_w : zoom_h;

    if (zoom > 0 && zoom < 256) {
        const int32_t scaled_w = (design_w * zoom) / 256;
        const int32_t scaled_h = (design_h * zoom) / 256;
        const int32_t x_off = (hor - scaled_w) / 2;
        const int32_t y_off = (ver - scaled_h) / 2;

        uint32_t i = 0;
        while (true) {
            lv_obj_t *child = lv_obj_get_child(screen, i);
            if (!child) break;
            rescale_obj_tree(child, zoom, (lv_coord_t)x_off, (lv_coord_t)y_off);
            i++;
        }
    }

    lv_obj_update_layout(screen);
    if (screen == objects._1) {
        disable_scrolling_recursive(screen);
    } else {
        disable_scrolling(screen);
    }
    lv_obj_add_flag(screen, LV_OBJ_FLAG_USER_4);
}

