static bool ui_programs_apply_store(const ui_program_store_t *st) {
    if (!st) return false;
    if (st->magic != 0x54524145U) return false;
    if (st->version != 2) return false;
    if (st->program_count > UI_MAX_PROGRAMS) return false;

    s_program_count = st->program_count;
    memcpy(s_program_names, st->program_names, sizeof(s_program_names));
    memcpy(s_program_steps_total, st->program_steps_total, sizeof(s_program_steps_total));
    memcpy(s_program_total_time_s, st->program_total_time_s, sizeof(s_program_total_time_s));
    memcpy(s_program_step_temp_c, st->program_step_temp_c, sizeof(s_program_step_temp_c));
    memcpy(s_program_step_rate_c_per_h_x10, st->program_step_rate_c_per_h_x10, sizeof(s_program_step_rate_c_per_h_x10));
    memcpy(s_program_step_hold_s, st->program_step_hold_s, sizeof(s_program_step_hold_s));

    for (uint8_t i = 0; i < UI_MAX_PROGRAMS; i++) {
        char clean[sizeof(s_program_names[i])];
        ui_copy_utf8_sanitized(clean, sizeof(clean), s_program_names[i]);
        memcpy(s_program_names[i], clean, sizeof(s_program_names[i]));
        if (s_program_steps_total[i] == 0) s_program_steps_total[i] = 1;
        if (s_program_steps_total[i] > UI_MAX_STEPS) s_program_steps_total[i] = UI_MAX_STEPS;
    }

    if (s_program_count == 0) {
        s_selected_program_id = 255;
        ui_set_selected_program_name("");
        ui_set_selected_program_steps_total(1);
        return true;
    }

    s_selected_program_id = (st->selected_id < s_program_count) ? st->selected_id : 0;
    ui_set_selected_program_name(ui_get_program_name(s_selected_program_id));
    ui_set_selected_program_steps_total(ui_get_program_steps_total(s_selected_program_id));
    return true;
}

static bool ui_programs_load_from_config_json(void) {
    FILE *f = fopen(CONFIG_FILE, "r");
    if (!f) return false;
    if (fseek(f, 0, SEEK_END) != 0) {
        fclose(f);
        return false;
    }
    const long size = ftell(f);
    if (size <= 0 || fseek(f, 0, SEEK_SET) != 0) {
        fclose(f);
        return false;
    }

    char *buf = (char *)malloc((size_t)size + 1U);
    if (!buf) {
        fclose(f);
        return false;
    }
    const size_t read_sz = fread(buf, 1, (size_t)size, f);
    fclose(f);
    buf[read_sz] = '\0';

    cJSON *root = cJSON_ParseWithLength(buf, read_sz);
    free(buf);
    if (!root || !cJSON_IsObject(root)) {
        if (root) cJSON_Delete(root);
        return false;
    }

    const cJSON *ui_programs = cJSON_GetObjectItemCaseSensitive(root, "ui_programs");
    const cJSON *programs = ui_programs ? cJSON_GetObjectItemCaseSensitive(ui_programs, "programs") : NULL;
    if (!cJSON_IsObject(ui_programs) || !cJSON_IsArray(programs)) {
        cJSON_Delete(root);
        return false;
    }

    ui_program_store_t st;
    memset(&st, 0, sizeof(st));
    st.magic = 0x54524145U;
    st.version = 2;

    const int arr_count = cJSON_GetArraySize(programs);
    if (arr_count < 0) {
        cJSON_Delete(root);
        return false;
    }
    st.program_count = (uint8_t)((arr_count > UI_MAX_PROGRAMS) ? UI_MAX_PROGRAMS : arr_count);

    const cJSON *selected_id = cJSON_GetObjectItemCaseSensitive(ui_programs, "selected_id");
    if (cJSON_IsNumber(selected_id) && selected_id->valuedouble >= 0.0) {
        st.selected_id = (uint8_t)selected_id->valueint;
    } else {
        st.selected_id = 0;
    }

    for (uint8_t i = 0; i < st.program_count; i++) {
        const cJSON *prog = cJSON_GetArrayItem(programs, i);
        if (!cJSON_IsObject(prog)) continue;

        const cJSON *name = cJSON_GetObjectItemCaseSensitive(prog, "name");
        if (cJSON_IsString(name) && name->valuestring) {
            ui_copy_utf8_trunc(st.program_names[i], sizeof(st.program_names[i]), name->valuestring);
        }

        uint16_t steps_total = 1;
        const cJSON *steps_total_item = cJSON_GetObjectItemCaseSensitive(prog, "steps_total");
        if (cJSON_IsNumber(steps_total_item) && steps_total_item->valuedouble > 0.0) {
            steps_total = (uint16_t)steps_total_item->valueint;
        }
        if (steps_total > UI_MAX_STEPS) steps_total = UI_MAX_STEPS;
        st.program_steps_total[i] = steps_total;

        const cJSON *total_time_s = cJSON_GetObjectItemCaseSensitive(prog, "total_time_s");
        if (cJSON_IsNumber(total_time_s) && total_time_s->valuedouble >= 0.0) {
            st.program_total_time_s[i] = (uint32_t)total_time_s->valuedouble;
        }

        const cJSON *steps = cJSON_GetObjectItemCaseSensitive(prog, "steps");
        if (!cJSON_IsArray(steps)) continue;
        const int steps_count = cJSON_GetArraySize(steps);
        const int capped_steps = (steps_count > steps_total) ? steps_total : steps_count;
        for (int j = 0; j < capped_steps; j++) {
            const cJSON *step = cJSON_GetArrayItem(steps, j);
            if (!cJSON_IsObject(step)) continue;
            const cJSON *temp_c = cJSON_GetObjectItemCaseSensitive(step, "temp_c");
            const cJSON *rate_x10 = cJSON_GetObjectItemCaseSensitive(step, "rate_c_per_h_x10");
            const cJSON *hold_s = cJSON_GetObjectItemCaseSensitive(step, "hold_s");
            if (cJSON_IsNumber(temp_c)) st.program_step_temp_c[i][j] = (int16_t)temp_c->valueint;
            if (cJSON_IsNumber(rate_x10) && rate_x10->valuedouble >= 0.0) {
                st.program_step_rate_c_per_h_x10[i][j] = (uint16_t)rate_x10->valueint;
            }
            if (cJSON_IsNumber(hold_s) && hold_s->valuedouble >= 0.0) {
                st.program_step_hold_s[i][j] = (uint32_t)hold_s->valuedouble;
            }
        }
    }

    cJSON_Delete(root);
    return ui_programs_apply_store(&st);
}

static bool ui_programs_save_to_config_json(void) {
    cJSON *root = NULL;
    FILE *f = fopen(CONFIG_FILE, "r");
    if (f) {
        if (fseek(f, 0, SEEK_END) == 0) {
            const long size = ftell(f);
            if (size > 0 && fseek(f, 0, SEEK_SET) == 0) {
                char *buf = (char *)malloc((size_t)size + 1U);
                if (buf) {
                    const size_t read_sz = fread(buf, 1, (size_t)size, f);
                    buf[read_sz] = '\0';
                    root = cJSON_ParseWithLength(buf, read_sz);
                    free(buf);
                }
            }
        }
        fclose(f);
    }
    if (!root || !cJSON_IsObject(root)) {
        if (root) cJSON_Delete(root);
        root = cJSON_CreateObject();
    }
    if (!root) return false;

    cJSON_DeleteItemFromObject(root, "ui_programs");
    cJSON *ui_programs = cJSON_AddObjectToObject(root, "ui_programs");
    cJSON_AddNumberToObject(ui_programs, "version", 2);
    cJSON_AddNumberToObject(ui_programs, "selected_id", s_selected_program_id);
    cJSON *programs = cJSON_AddArrayToObject(ui_programs, "programs");
    for (uint8_t i = 0; i < s_program_count; i++) {
        cJSON *prog = cJSON_CreateObject();
        cJSON_AddStringToObject(prog, "name", s_program_names[i]);
        cJSON_AddNumberToObject(prog, "steps_total", s_program_steps_total[i]);
        cJSON_AddNumberToObject(prog, "total_time_s", (double)s_program_total_time_s[i]);
        cJSON *steps = cJSON_AddArrayToObject(prog, "steps");
        const uint16_t total = ui_get_program_steps_total(i);
        for (uint16_t j = 0; j < total; j++) {
            cJSON *step = cJSON_CreateObject();
            cJSON_AddNumberToObject(step, "temp_c", s_program_step_temp_c[i][j]);
            cJSON_AddNumberToObject(step, "rate_c_per_h_x10", s_program_step_rate_c_per_h_x10[i][j]);
            cJSON_AddNumberToObject(step, "hold_s", (double)s_program_step_hold_s[i][j]);
            cJSON_AddItemToArray(steps, step);
        }
        cJSON_AddItemToArray(programs, prog);
    }

    char *rendered = cJSON_PrintUnformatted(root);
    cJSON_Delete(root);
    if (!rendered) return false;

    const char *tmp_path = CONFIG_FILE ".tmp";
    FILE *out = fopen(tmp_path, "w");
    if (!out) {
        free(rendered);
        return false;
    }
    const size_t len = strlen(rendered);
    const size_t written = fwrite(rendered, 1, len, out);
    fflush(out);
    fclose(out);
    free(rendered);
    if (written != len) {
        (void)remove(tmp_path);
        return false;
    }
    if (rename(tmp_path, CONFIG_FILE) != 0) {
        (void)remove(CONFIG_FILE);
        if (rename(tmp_path, CONFIG_FILE) != 0) {
            (void)remove(tmp_path);
            return false;
        }
    }
    return true;
}

void ui_set_selected_program_name(const char *name);
void ui_set_selected_program_steps_total(uint16_t steps);
const char *ui_get_program_name(uint8_t id);
uint16_t ui_get_program_steps_total(uint8_t id);

static void ui_programs_persist_load() {
    if (ui_programs_load_from_config_json()) return;

    nvs_handle_t h = 0;
    if (nvs_open("ui", NVS_READONLY, &h) != ESP_OK) return;
    ui_program_store_t st = { 0 };
    size_t sz = sizeof(st);
    const esp_err_t err = nvs_get_blob(h, "programs_v2", &st, &sz);
    nvs_close(h);
    if (err != ESP_OK) return;
    if (ui_programs_apply_store(&st)) {
        (void)ui_programs_save_to_config_json();
    }
}

static void ui_display_persist_load() {
    nvs_handle_t h = 0;
    if (nvs_open("ui", NVS_READONLY, &h) != ESP_OK) return;
    uint16_t sleep_min = 0;
    if (nvs_get_u16(h, "sleep_min", &sleep_min) == ESP_OK) {
        s_display_sleep_minutes = sleep_min;
    }
    uint8_t v = 0;
    if (nvs_get_u8(h, "date_fmt", &v) == ESP_OK && v <= (uint8_t)UI_DATE_FORMAT_YYYYMMDD) {
        s_date_format = (ui_date_format_t)v;
    }
    if (nvs_get_u8(h, "time_fmt", &v) == ESP_OK && v <= (uint8_t)UI_TIME_FORMAT_12H) {
        s_time_format = (ui_time_format_t)v;
    }
    if (nvs_get_u8(h, "temp_unit", &v) == ESP_OK && v <= (uint8_t)UI_TEMP_UNIT_F) {
        s_temp_unit = (ui_temp_unit_t)v;
    }
    if (nvs_get_u8(h, "lang_en", &v) == ESP_OK) {
        s_is_english = (v != 0);
    }
    nvs_close(h);
}

static void ui_display_persist_save() {
    nvs_handle_t h = 0;
    if (nvs_open("ui", NVS_READWRITE, &h) != ESP_OK) return;
    (void)nvs_set_u16(h, "sleep_min", s_display_sleep_minutes);
    (void)nvs_set_u8(h, "date_fmt", (uint8_t)s_date_format);
    (void)nvs_set_u8(h, "time_fmt", (uint8_t)s_time_format);
    (void)nvs_set_u8(h, "temp_unit", (uint8_t)s_temp_unit);
    (void)nvs_set_u8(h, "lang_en", s_is_english ? 1U : 0U);
    (void)nvs_commit(h);
    nvs_close(h);
}

