void ui_set_selected_program_breakpoints(const int16_t *temps, const uint32_t *times, uint8_t count) {
    if (count > 8) count = 8;
    s_selected_program_bp_count = count;
    for (uint8_t i = 0; i < 8; i++) {
        if (i < count) {
            s_selected_program_bp_temps[i] = temps ? temps[i] : 0;
            s_selected_program_bp_times[i] = times ? times[i] : 0;
        } else {
            s_selected_program_bp_temps[i] = 0;
            s_selected_program_bp_times[i] = 0;
        }
    }
}

