void ui_init() {
#if defined(ESP_PLATFORM)
    ui_try_promote_program_storage_to_psram();
#endif
    ui_programs_persist_load();
    ui_display_persist_load();
    create_screens();
    loadScreen(SCREEN_ID__1);
#if defined(ESP_PLATFORM)
    s_display_last_user_activity_ms = lv_tick_get();
#endif
}

void ui_tick() {
    if (s_pending_lang_toggle) {
        s_pending_lang_toggle = false;
        s_is_english = !s_is_english;
        ui_display_persist_save();

        enum ScreensEnum target = (enum ScreensEnum)(currentScreen + 1);
        if (target == (enum ScreensEnum)0) target = SCREEN_ID__1;
        ui_load_screen_fresh(target);
    }

    if (s_pending_screen != (enum ScreensEnum)0) {
        const enum ScreensEnum id = s_pending_screen;
        s_pending_screen = (enum ScreensEnum)0;
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_nav, "ui_tick: consume pending screen=%d current=%d sel_id=%u sel_name='%s' steps=%u",
                 (int)id, (int)(currentScreen + 1), (unsigned)s_selected_program_id, s_selected_program_name,
                 (unsigned)s_selected_program_steps_total);
#endif
        ui_load_screen_fresh(id);
    }

    if (s_programs_persist_deferred && !s_screen_transition_active && s_pending_screen == (enum ScreensEnum)0) {
        s_programs_persist_deferred = false;
        ui_programs_persist_save_impl();
    }

#if defined(ESP_PLATFORM)
    static uint32_t s_last_screen_tick_ms = 0;
    const uint32_t now_ms = lv_tick_get();
#else
    static uint32_t s_last_screen_tick_ms = 0;
    const uint32_t now_ms = lv_tick_get();
#endif

#if defined(ESP_PLATFORM)
    const uint32_t inactive_ms = lv_disp_get_inactive_time(NULL);

    if (s_display_sleep_minutes == 0) {
        if (s_display_sleeping) {
            display_driver_set_backlight_percent_forced(s_display_sleep_restore_brightness);
            s_display_sleeping = false;
            s_last_display_wake_ms = now_ms;
            ui_indev_quiesce();
        }
    } else {
        const uint32_t threshold_ms = (uint32_t)s_display_sleep_minutes * 60u * 1000u;
        if (now_ms < 5000) {
            if (s_display_sleeping) {
                display_driver_set_backlight_percent_forced(s_display_sleep_restore_brightness);
                s_display_sleeping = false;
                s_last_display_wake_ms = now_ms;
                ui_indev_quiesce();
            }
        } else if (!s_display_sleeping && inactive_ms >= threshold_ms) {
            s_display_sleep_restore_brightness = display_driver_get_backlight_percent();
            if (s_display_sleep_restore_brightness > 0) {
                display_driver_set_backlight_percent_forced(0);
            }
            s_display_sleeping = true;
            ui_indev_quiesce();
        } else if (s_display_sleeping && inactive_ms < 2000) {
            display_driver_set_backlight_percent_forced(s_display_sleep_restore_brightness);
            s_display_sleeping = false;
            s_last_display_wake_ms = now_ms;
            ui_indev_quiesce();
        }
    }
#endif

    if ((uint32_t)(now_ms - s_last_screen_tick_ms) >= 50) {
        s_last_screen_tick_ms = now_ms;
        tick_screen(currentScreen);
    }
}
